// --- Sub-componente: Renderizador de PDF ---
const PDFRenderer: React.FC<{ file?: File }> = ({ file }) => {
    const [pages, setPages] = useState<number[]>([]);
    const [pdfInstance, setPdfInstance] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!file) return;

        const loadPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) {
                setError("Biblioteca PDF não carregada. Recarregue a página.");
                return;
            }
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
            } catch (err: any) { 
                console.error("PDF Load error:", err); 
                setError("Erro ao renderizar PDF. Use a visualização de tabela.");
            }
        };
        loadPDF();
    }, [file]);

    if (!file) return null;

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                <XMarkIcon className="w-10 h-10 mb-2 opacity-50" />
                <p className="text-xs">{error}</p>
            </div>
        );
    }

    const PageCanvas: React.FC<{ pageNum: number, pdf: any }> = ({ pageNum, pdf }) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);
        useEffect(() => {
            const render = async () => {
                if (!pdf || !canvasRef.current) return;
                try {
                    const page = await pdf.getPage(pageNum);
                    // Escala ajustada para caber melhor na tela
                    const viewport = page.getViewport({ scale: 1.0 }); 
                    const canvas = canvasRef.current;
                    const context = canvas.getContext('2d');
                    if (context) {
                        canvas.height = viewport.height;
                        canvas.width = viewport.width;
                        await page.render({ canvasContext: context, viewport }).promise;
                    }
                } catch (e) { console.error(e); }
            };
            render();
        }, [pageNum, pdf]);
        return (
            <div className="bg-white p-1 shadow-sm border border-slate-200 mb-4 rounded-sm w-fit max-w-full overflow-hidden mx-auto">
                <canvas ref={canvasRef} className="max-w-full h-auto block" />
            </div>
        );
    };

    return (
        <div className="absolute inset-0 overflow-auto custom-scrollbar bg-slate-200 dark:bg-slate-950/50 p-4">
            {pages.map(p => <PageCanvas key={p} pageNum={p} pdf={pdfInstance} />)}
            {pages.length === 0 && !error && (
                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                    <ArrowPathIcon className="w-8 h-8 animate-spin mb-3" />
                    <p className="text-[10px] font-bold uppercase tracking-widest">Renderizando PDF...</p>
                </div>
            )}
        </div>
    );
};

// --- Sub-componente: Renderizador de Planilha (Excel Grid Style) ---
const SpreadsheetRenderer: React.FC<{ data: string[][], isLoading?: boolean, detectedMapping?: any }> = ({ data, isLoading, detectedMapping }) => {

    const getColumnLabel = (index: number) => {
        let label = '';
        let i = index;
        while (i >= 0) {
            label = String.fromCharCode((i % 26) + 65) + label;
            i = Math.floor(i / 26) - 1;
        }
        return label;
    };

    const getColumnHighlight = (index: number) => {
        if (!detectedMapping) return '';
        if (index === detectedMapping.dateColumnIndex) return 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800';
        if (index === detectedMapping.amountColumnIndex) return 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800';
        if (index === detectedMapping.descriptionColumnIndex) return 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800';
        return '';
    };

    const getColumnHeaderHighlight = (index: number) => {
        if (!detectedMapping) return '';
        if (index === detectedMapping.dateColumnIndex) return 'bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300';
        if (index === detectedMapping.amountColumnIndex) return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900 dark:text-emerald-300';
        if (index === detectedMapping.descriptionColumnIndex) return 'bg-purple-100 text-purple-700 dark:bg-purple-900 dark:text-purple-300';
        return '';
    }

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400">
                <ArrowPathIcon className="w-8 h-8 animate-spin mb-2" />
                <p className="text-[10px] font-bold uppercase">Carregando dados...</p>
            </div>
        );
    }

    if (!data || data.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center bg-slate-50 dark:bg-slate-900/50">
                <ExclamationTriangleIcon className="w-12 h-12 mb-3 opacity-20" />
                <p className="text-sm font-bold text-slate-500 dark:text-slate-300">Visualização indisponível</p>
                <p className="text-xs mt-2 max-w-xs mx-auto opacity-70">
                    Não foi possível renderizar o conteúdo deste arquivo.
                </p>
            </div>
        );
    }

    const maxCols = data.reduce((max, row) => Math.max(max, row.length), 0);
    const colIndices = Array.from({ length: maxCols }, (_, i) => i);

    // USANDO ABSOLUTE INSET-0 PARA GARANTIR SCROLL INTERNO SEM ESTOURAR O PAI
    return (
        <div className="absolute inset-0 overflow-auto custom-scrollbar bg-[#f8f9fa] dark:bg-[#1e1e1e] select-text">
            <table className="border-collapse table-fixed min-w-full">
                <thead className="sticky top-0 z-20">
                    <tr>
                        <th className="w-10 min-w-[40px] bg-[#e6e6e6] dark:bg-[#333] border-r border-b border-[#c0c0c0] dark:border-[#555] sticky left-0 z-30"></th>
                        {colIndices.map(colIndex => (
                            <th key={colIndex} className={`bg-[#f0f0f0] dark:bg-[#2d2d2d] border-r border-b border-[#d4d4d4] dark:border-[#555] text-center text-[10px] font-bold text-slate-600 dark:text-slate-300 h-6 min-w-[100px] select-none ${getColumnHeaderHighlight(colIndex)}`}>
                                {getColumnLabel(colIndex)}
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {data.slice(0, 500).map((row, rowIndex) => (
                        <tr key={rowIndex} className="h-6">
                            <td className="sticky left-0 z-10 bg-[#f0f0f0] dark:bg-[#2d2d2d] border-r border-b border-[#d4d4d4] dark:border-[#555] text-center text-[10px] font-bold text-slate-600 dark:text-slate-300 select-none w-10">
                                {rowIndex + 1}
                            </td>
                            {colIndices.map(colIndex => (
                                <td 
                                    key={`${rowIndex}-${colIndex}`} 
                                    className={`border-r border-b border-[#e0e0e0] dark:border-[#444] px-2 py-0.5 text-xs text-slate-800 dark:text-slate-200 whitespace-nowrap overflow-hidden text-ellipsis empty:bg-white dark:empty:bg-[#121212] focus:outline-none hover:bg-slate-100 dark:hover:bg-slate-800 cursor-cell ${getColumnHighlight(colIndex)}`}
                                    title={row[colIndex]}
                                >
                                    {row[colIndex]}
                                </td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const formatToBRL = (val: string | number) => {
    const num = typeof val === 'string' ? parseFloat(val) : val;
    if (isNaN(num)) return '0,00';
    return num.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const getColumnOptions = (count: number) => {
    return Array.from({ length: count }, (_, i) => {
        let label = '';
        let n = i;
        while (n >= 0) {
            label = String.fromCharCode((n % 26) + 65) + label;
            n = Math.floor(n / 26) - 1;
        }
        return { value: i, label: `Coluna ${label}` };
    });
};

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const { effectiveIgnoreKeywords, contributionKeywords } = useContext(AppContext);

    // --- STATE MANAGEMENT ---

    const [localFile, setLocalFile] = useState<{ content: string; fileName: string; rawFile?: File } | null>(null);
    const activeFile = initialFile || localFile;

    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);

    const [processedTransactions, setProcessedTransactions] = useState<Transaction[]>([]);
    const [strategyUsed, setStrategyUsed] = useState<string>('Aguardando Mapeamento...');

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [modelName, setModelName] = useState(initialModel?.name || '');
    const [activeMapping, setActiveMapping] = useState<any>(null); 
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);

    const isPdf = useMemo(() => activeFile?.fileName?.toLowerCase().endsWith('.pdf'), [activeFile]);
    const isImage = useMemo(() => /\.(jpg|jpeg|png|webp)$/i.test(activeFile?.fileName || ''), [activeFile]);
    const isTestMode = mode === 'test';

    const cleaningKeywords = useMemo(() => {
        return [...effectiveIgnoreKeywords, ...contributionKeywords];
    }, [effectiveIgnoreKeywords, contributionKeywords]);

    // --- UPLOAD HANDLER (INTERNAL) ---
    const handleInternalFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        setIsGridLoading(true);
        try {
            let content = '';
            const fName = file.name.toLowerCase();

            if (fName.endsWith('.pdf') || fName.endsWith('.xlsx') || fName.endsWith('.xls') || /\.(jpg|jpeg|png|webp)$/i.test(fName)) {
                content = '';
            } else {
                content = await file.text();
            }

            setLocalFile({
                content,
                fileName: file.name,
                rawFile: file
            });
        } catch (error: any) {
            console.error("Erro ao ler arquivo interno:", error);
            showToast("Erro ao ler arquivo: " + error.message, "error");
            setIsGridLoading(false);
        }
    };

    // --- SIMULADOR DE ESTRATÉGIA ---
    const runSimulation = useCallback(() => {
        if (!gridData.length || !activeMapping) {
            showToast("Carregue um arquivo e defina o mapeamento primeiro.", "error");
            return;
        }

        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = activeMapping;
        const newTransactions: Transaction[] = [];
        const yearAnchor = new Date().getFullYear();

        const dataLines = gridData.slice(skipRowsStart || 0);

        dataLines.forEach((cols, index) => {
            if (cols.length <= Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) return;

            const rawDate = cols[dateColumnIndex];
            const rawDesc = cols[descriptionColumnIndex];
            const rawAmount = cols[amountColumnIndex];
            const rawType = typeColumnIndex !== undefined ? cols[typeColumnIndex] : '';

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);

            if (isoDate && !isNaN(amount) && amount !== 0) {
                const cleanedDesc = NameResolver.clean(rawDesc, cleaningKeywords);
                const finalType = rawType ? rawType.trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);

                newTransactions.push({
                    id: `sim-${index}`,
                    date: isoDate,
                    description: rawDesc,
                    amount: amount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanedDesc,
                    contributionType: finalType
                });
            }
        });

        setProcessedTransactions(newTransactions);
        setStrategyUsed(isTestMode ? `Validação: ${initialModel?.name}` : "Simulação Ativa (Manual)");

    }, [gridData, activeMapping, cleaningKeywords, isTestMode, initialModel, showToast]);

    // --- EFFECT: Load and Process Content ---
    useEffect(() => {
        if (!activeFile) return;

        const loadContent = async () => {
            setIsGridLoading(true);
            let loadedRows: string[][] = [];

            // Caso 1: PDF - Visualização Fiel via PDFRenderer
            if (isPdf && activeFile.rawFile) {
                // PDF processing handled by PDFRenderer component
            }

            // Caso 2: Excel Real
            else if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                try {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    const ws = wb.Sheets[wb.SheetNames[0]];
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(ws, { header: 1, defval: '' });
                } catch (e) {
                    console.error("Erro ao ler Excel:", e);
                }
            } 
            // Caso 3: CSV/Texto
            else if (!isPdf && !isImage) {
                const lines = (activeFile.content || '').split(/\r?\n/).filter((l: string) => l.trim().length > 0);
                if (lines.length > 0) {
                    const delimiter = detectDelimiter(lines[0]);
                    loadedRows = lines.map((l: string) => l.split(delimiter));
                }
            }

            // Set Data if available (Excel/CSV/TXT)
            if (loadedRows.length > 0) {
                setGridData(loadedRows);

                const contentForFp = (activeFile.content || loadedRows.slice(0, 5).map(r => r.join(';')).join('\n'));
                const fp = generateFingerprint(contentForFp);
                setDetectedFingerprint(fp);

                // IMPORTANTE: Só ativa mapeamento se for edição. 
                // Novos arquivos começam SEM mapeamento (sem inferência automática).
                if (initialModel && initialModel.mapping) {
                    setActiveMapping(initialModel.mapping);
                } else {
                    setActiveMapping(null);
                }
            } else {
                setGridData([]);
                setDetectedFingerprint(null);
                setActiveMapping(null);
            }

            setIsGridLoading(false);
        };

        loadContent();

    }, [activeFile, isPdf, isImage, initialModel]);

    // --- HANDLER: Save Model ---
    const handleSaveModel = async (approvalStatus: 'draft' | 'approved') => {
        if (!modelName.trim()) {
            showToast("Digite um nome para o modelo.", "error");
            return;
        }
        if (!activeMapping || !detectedFingerprint) {
            showToast("Não foi possível detectar um padrão claro para salvar.", "error");
            return;
        }
        if (!user) {
            showToast("Você precisa estar logado.", "error");
            return;
        }

        setIsSavingModel(true);
        try {
            const newModel: Omit<FileModel, 'id' | 'createdAt'> = {
                name: modelName,
                user_id: user.id,
                version: initialModel ? initialModel.version + 1 : 1,
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`,
                is_active: true,
                fingerprint: detectedFingerprint,
                mapping: activeMapping,
                parsingRules: {
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [],
                    rowFilters: []
                },
                snippet: activeFile?.content?.substring(0, 2000) || '',
                lastUsedAt: new Date().toISOString(),
                status: approvalStatus,
                approvedBy: approvalStatus === 'approved' ? user.id : undefined,
                approvedAt: approvalStatus === 'approved' ? new Date().toISOString() : undefined
            };

            const saved = await modelService.saveModel(newModel);

            if (approvalStatus === 'approved') {
                showToast("Modelo aprovado e pronto para uso!", "success");
            } else {
                showToast("Rascunho salvo com sucesso.", "success");
            }

            if (onSuccess && saved) {
                onSuccess(saved as FileModel, processedTransactions);
            } else {
                onClose(); 
            }
        } catch (error: any) {
            console.error("Erro ao salvar modelo:", error);
            showToast("Erro ao salvar modelo: " + error.message, "error");
        } finally {
            setIsSavingModel(false);
        }
    };

    const columnOptions = useMemo(() => {
        if (gridData.length === 0) return [];
        const maxCols = gridData.reduce((max, row) => Math.max(max, row.length), 0);
        return getColumnOptions(maxCols);
    }, [gridData]);

    // RENDERIZAÇÃO SE NÃO HOUVER ARQUIVO (UPLOAD INICIAL)
    if (!activeFile) {
        return (
            <div className="fixed inset-0 z-[1000] bg-[#050B14]/90 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in">
                <div className="bg-white dark:bg-[#0F172A] w-full max-w-xl rounded-3xl shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative p-8">
                    <div className="flex justify-between items-center mb-6 shrink-0">
                        <h3 className="text-xl font-black text-slate-800 dark:text-white">Criar Novo Modelo</h3>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>

                    <div className="flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl bg-slate-50 dark:bg-slate-900/50 hover:border-indigo-500 dark:hover:border-indigo-500 transition-colors group relative cursor-pointer min-h-[240px]">
                        <input 
                            type="file" 
                            className="absolute inset-0 opacity-0 cursor-pointer z-10 w-full h-full"
                            onChange={handleInternalFileUpload}
                            accept=".csv,.txt,.xlsx,.xls,.pdf,.jpg,.jpeg,.png,.webp"
                        />
                        <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 rounded-full text-indigo-500 group-hover:scale-110 transition-transform duration-300">
                            <UploadIcon className="w-8 h-8" />
                        </div>
                        <p className="mt-4 text-sm font-bold text-slate-600 dark:text-slate-300">
                            Arraste ou clique para selecionar
                        </p>
                        <p className="mt-2 text-xs text-slate-400">
                            Suporta CSV, Excel (XLSX), PDF, TXT e Imagens
                        </p>
                    </div>
                </div>
            </div>
        );
    }

    // RENDERIZAÇÃO PRINCIPAL (LABORATÓRIO)
    return (
        <div className="fixed inset-0 z-[1000] bg-[#050B14]/90 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            {/* 
               MODAL CONTAINER:
               - max-h-[95dvh]: Altura dinâmica que respeita viewport móvel.
               - flex flex-col: Garante que header/body/footer não se sobreponham.
               - overflow-hidden: Impede scroll no container principal (scrolls apenas internos).
            */}
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-xl sm:rounded-3xl shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                {/* Header (Fixo) */}
                <div className="px-4 md:px-6 py-4 bg-slate-100 dark:bg-[#020610] border-b border-slate-200 dark:border-slate-800 flex flex-col sm:flex-row justify-between items-center shrink-0 gap-3 z-20">
                    <div className="flex items-center gap-4 w-full sm:w-auto">
                        <div className={`p-2.5 rounded-xl ${isTestMode ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' : 'bg-amber-500/10 text-amber-500 border-amber-500/20'} border`}>
                            {isTestMode ? <PlayCircleIcon className="w-5 h-5" /> : <WrenchScrewdriverIcon className="w-5 h-5" />}
                        </div>
                        <div className="min-w-0">
                            <h3 className="text-lg font-black text-slate-800 dark:text-white tracking-tight flex items-center gap-2 flex-wrap">
                                <span className="truncate">Laboratório</span>
                                <span className={`px-2 py-0.5 rounded text-[10px] uppercase tracking-wider whitespace-nowrap ${isTestMode ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300' : 'bg-slate-200 dark:bg-slate-800 text-slate-500'}`}>
                                    {isTestMode ? 'Validação' : 'Aprendizado'}
                                </span>
                            </h3>
                            <div className="flex items-center gap-2 text-xs text-slate-500 dark:text-slate-400">
                                <span className="font-mono text-amber-600 dark:text-amber-400 truncate max-w-[200px]">{activeFile?.fileName}</span>
                                <span className="hidden sm:inline">•</span>
                                <span className="hidden sm:inline">Status: <strong className="text-emerald-600 dark:text-emerald-400">{strategyUsed}</strong></span>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-2 w-full sm:w-auto justify-end">
                        {activeMapping && gridData.length > 0 && !isTestMode && (
                            <div className="flex items-center bg-white dark:bg-slate-900 rounded-full border border-slate-200 dark:border-slate-700 p-1 pl-3 shadow-sm flex-1 sm:flex-none min-w-0">
                                <input 
                                    type="text" 
                                    placeholder="Nome do Modelo" 
                                    value={modelName}
                                    onChange={(e) => setModelName(e.target.value)}
                                    className="bg-transparent text-xs outline-none text-slate-700 dark:text-slate-200 w-full sm:w-32 md:w-48 placeholder:text-slate-400 min-w-0"
                                />
                                <div className="flex gap-1 ml-2 shrink-0">
                                    <button 
                                        onClick={() => handleSaveModel('draft')} 
                                        disabled={isSavingModel || !modelName.trim()}
                                        className="px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 dark:bg-slate-800 dark:hover:bg-slate-700 dark:text-slate-300 rounded-full text-[10px] font-bold uppercase transition-all disabled:opacity-50"
                                    >
                                        <span>Rascunho</span>
                                    </button>
                                    <button 
                                        onClick={() => handleSaveModel('approved')} 
                                        disabled={isSavingModel || !modelName.trim()}
                                        className="px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-bold uppercase transition-all disabled:opacity-50 flex items-center gap-1"
                                    >
                                        {isSavingModel ? <ArrowPathIcon className="w-3 h-3 animate-spin" /> : <ShieldCheckIcon className="w-3 h-3" />}
                                        <span className="hidden sm:inline">Aprovar</span>
                                    </button>
                                </div>
                            </div>
                        )}

                        {isTestMode && (
                            <button 
                                onClick={onClose} 
                                className="px-4 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-full text-[10px] font-bold uppercase transition-all flex items-center gap-2"
                            >
                                <XMarkIcon className="w-4 h-4" /> Fechar Teste
                            </button>
                        )}

                        {!isTestMode && (
                            <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors shrink-0">
                                <XMarkIcon className="w-6 h-6" />
                            </button>
                        )}
                    </div>
                </div>

                {/* Main Workspace (Flexível) */}
                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden relative min-h-0">

                    {/* LEFT PANEL: RAW SOURCE */}
                    <div className="flex-1 flex flex-col min-h-0 border-b lg:border-b-0 lg:border-r border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-[#0B1120] lg:w-1/2">

                        {/* Controles de Mapeamento (Sticky Header do Painel) */}
                        {activeMapping && gridData.length > 0 && (
                            <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm flex flex-wrap gap-3 items-center z-20 shrink-0">
                                <div className="flex items-center gap-2 w-full sm:w-auto">
                                    <div className="p-1.5 bg-blue-100 dark:bg-blue-900/30 rounded text-blue-600 dark:text-blue-400">
                                        <AdjustmentsHorizontalIcon className="w-3 h-3" />
                                    </div>
                                    <span className="text-[10px] font-bold uppercase text-slate-500">Mapeamento:</span>
                                </div>

                                <div className="flex flex-wrap gap-2 items-center flex-1">
                                    {/* Data */}
                                    <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 rounded-lg p-1 border border-slate-200 dark:border-slate-700 shadow-sm">
                                        <label className="text-[9px] font-bold text-blue-600 dark:text-blue-400 uppercase px-1">Data</label>
                                        <select 
                                            value={activeMapping.dateColumnIndex}
                                            onChange={(e) => setActiveMapping({...activeMapping, dateColumnIndex: parseInt(e.target.value)})}
                                            disabled={isTestMode}
                                            className="bg-transparent text-xs outline-none w-20 sm:w-24 text-slate-700 dark:text-slate-200"
                                        >
                                            {columnOptions.map(opt => <option key={`d-${opt.value}`} value={opt.value}>{opt.label}</option>)}
                                        </select>
                                    </div>

                                    {/* Desc */}
                                    <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 rounded-lg p-1 border border-slate-200 dark:border-slate-700 shadow-sm">
                                        <label className="text-[9px] font-bold text-purple-600 dark:text-purple-400 uppercase px-1">Desc</label>
                                        <select 
                                            value={activeMapping.descriptionColumnIndex}
                                            onChange={(e) => setActiveMapping({...activeMapping, descriptionColumnIndex: parseInt(e.target.value)})}
                                            disabled={isTestMode}
                                            className="bg-transparent text-xs outline-none w-20 sm:w-24 text-slate-700 dark:text-slate-200"
                                        >
                                            {columnOptions.map(opt => <option key={`desc-${opt.value}`} value={opt.value}>{opt.label}</option>)}
                                        </select>
                                    </div>

                                    {/* Valor */}
                                    <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 rounded-lg p-1 border border-slate-200 dark:border-slate-700 shadow-sm">
                                        <label className="text-[9px] font-bold text-emerald-600 dark:text-emerald-400 uppercase px-1">Valor</label>
                                        <select 
                                            value={activeMapping.amountColumnIndex}
                                            onChange={(e) => setActiveMapping({...activeMapping, amountColumnIndex: parseInt(e.target.value)})}
                                            disabled={isTestMode}
                                            className="bg-transparent text-xs outline-none w-20 sm:w-24 text-slate-700 dark:text-slate-200"
                                        >
                                            {columnOptions.map(opt => <option key={`amt-${opt.value}`} value={opt.value}>{opt.label}</option>)}
                                        </select>
                                    </div>

                                    {/* Pular Linhas */}
                                    <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 rounded-lg p-1 border border-slate-200 dark:border-slate-700 shadow-sm">
                                        <label className="text-[9px] font-bold text-slate-500 uppercase px-1">Pular</label>
                                        <input 
                                            type="number" 
                                            min="0" 
                                            max="50"
                                            value={activeMapping.skipRowsStart}
                                            onChange={(e) => setActiveMapping({...activeMapping, skipRowsStart: parseInt(e.target.value)})}
                                            disabled={isTestMode}
                                            className="w-10 bg-transparent text-xs outline-none text-center text-slate-700 dark:text-slate-200"
                                        />
                                    </div>
                                </div>

                                <div className="ml-auto w-full sm:w-auto">
                                    <button 
                                        onClick={runSimulation}
                                        disabled={!activeMapping || gridData.length === 0}
                                        className="w-full sm:w-auto flex items-center justify-center gap-2 px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-[10px] font-bold uppercase shadow-md transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                                        title="Rodar simulação com o mapeamento atual"
                                    >
                                        <PlayCircleIcon className="w-3.5 h-3.5" />
                                        <span>Simular</span>
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* Conteúdo (Scrollable Area) */}
                        <div className="flex-1 relative bg-white dark:bg-[#0B1120] overflow-hidden min-h-0">
                            {isPdf && activeFile?.rawFile ? (
                                <div className="absolute inset-0">
                                    <PDFRenderer file={activeFile.rawFile} />
                                </div>
                            ) : isImage && activeFile?.rawFile ? (
                                <ImageRenderer file={activeFile.rawFile} />
                            ) : (
                                <SpreadsheetRenderer data={gridData} isLoading={isGridLoading} detectedMapping={activeMapping} />
                            )}
                        </div>
                    </div>

                    {/* RIGHT PANEL: OUTPUT */}
                    <div className="flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0F172A] lg:w-1/2">
                        <div className="px-4 py-2 border-b border-slate-200 dark:border-slate-800 bg-emerald-50/50 dark:bg-emerald-900/10 text-[10px] font-bold uppercase tracking-widest text-emerald-700 dark:text-emerald-400 flex justify-between items-center shadow-sm z-10 shrink-0">
                            <div className="flex items-center gap-2">
                                <CodeBracketSquareIcon className="w-4 h-4" />
                                <span>Resultado Simulado {isTestMode ? '(Validação)' : '(Tempo Real)'}</span>
                            </div>
                            <span>{processedTransactions.length} Transações</span>
                        </div>

                        <div className="flex-1 overflow-auto custom-scrollbar p-0 min-h-0">
                            {processedTransactions.length > 0 ? (
                                <table className="w-full text-xs text-left border-collapse">
                                    <thead className="sticky top-0 bg-white dark:bg-slate-900 z-10 border-b border-slate-200 dark:border-slate-700 shadow-sm">
                                        <tr>
                                            <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24 bg-white dark:bg-slate-900">Data</th>
                                            <th className="p-3 font-bold text-slate-500 dark:text-slate-400 bg-white dark:bg-slate-900">Descrição (Limpa)</th>
                                            <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24 bg-white dark:bg-slate-900">Tipo</th>
                                            <th className="p-3 font-bold text-slate-500 dark:text-slate-400 text-right w-28 bg-white dark:bg-slate-900">Valor</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800/50">
                                        {processedTransactions.map((tx, idx) => (
                                            <tr key={tx.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                                                <td className="p-3 font-mono text-slate-600 dark:text-slate-300">
                                                    {tx.date.split('-').reverse().join('/')}
                                                </td>
                                                <td className="p-3">
                                                    <div className="font-bold text-slate-800 dark:text-slate-200">{tx.cleanedDescription}</div>
                                                    <div className="text-[9px] text-slate-400 truncate max-w-[300px] mt-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
                                                        Original: {tx.description}
                                                    </div>
                                                </td>
                                                <td className="p-3">
                                                    <span className="px-2 py-0.5 bg-slate-100 dark:bg-slate-800 text-slate-500 text-[10px] font-bold rounded uppercase">
                                                        {tx.contributionType || 'OUTROS'}
                                                    </span>
                                                </td>
                                                <td className={`p-3 text-right font-mono font-bold ${tx.amount < 0 ? 'text-red-500' : 'text-emerald-600 dark:text-emerald-400'}`}>
                                                    {formatToBRL(tx.amount)}
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            ) : (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                                    <DocumentArrowDownIcon className="w-12 h-12 mb-3 opacity-20" />
                                    <p className="text-sm font-bold text-slate-500 dark:text-slate-300">
                                        {strategyUsed.includes('Aguardando') ? 'Aguardando simulação' : 'Nenhum dado encontrado'}
                                    </p>
                                    <p className="text-xs mt-2 max-w-xs mx-auto opacity-70">
                                        {strategyUsed.includes('Aguardando') 
                                            ? 'Configure o mapeamento e clique em "Simular Resultado".' 
                                            : 'O mapeamento atual não retornou transações válidas.'}
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer (Fixo) */}
                <div className="px-4 md:px-6 py-3 bg-slate-100 dark:bg-[#020610] border-t border-slate-200 dark:border-slate-800 text-[10px] text-slate-500 dark:text-slate-400 flex justify-between items-center shrink-0 z-20">
                    <div className="flex items-center gap-4">
                        <span className="flex items-center gap-1.5">
                            <span className={`w-2 h-2 rounded-full ${isTestMode ? 'bg-amber-500' : 'bg-emerald-500'} animate-pulse`}></span>
                            {isTestMode ? 'Ambiente de Teste Seguro' : 'Visualização Fiel'}
                        </span>
                    </div>
                    {!isTestMode && (
                        <div className="flex items-center gap-2">
                            <BrainIcon className="w-3.5 h-3.5 text-indigo-500" />
                            <span className="hidden sm:inline">Ensine o sistema salvando este modelo.</span>
                            <span className="sm:hidden">Salvar modelo para aprender.</span>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useContext, useState, useMemo, useEffect, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EmptyState } from '../components/EmptyState';
import { EditableReportTable } from '../components/reports/EditableReportTable';
import { 
    ChartBarIcon, 
    BuildingOfficeIcon, 
    ExclamationTriangleIcon, 
    BanknotesIcon, 
    FloppyDiskIcon, 
    DocumentDuplicateIcon,
    MagnifyingGlassIcon,
    ChevronLeftIcon,
    ChevronRightIcon,
    PrinterIcon,
    DocumentArrowDownIcon,
    FolderPlusIcon // Added
} from '../components/Icons';
import { formatCurrency, formatDate } from '../utils/formatters';
import { MatchResult } from '../types';

export const ReportsView: React.FC = () => {
    const { 
        reportPreviewData, 
        activeReportId, 
        saveCurrentReportChanges, 
        openSaveReportModal, 
        matchResults,
        updateReportData,
        loadingAiId,
        openSmartEdit,
        openUpdateFilesModal // Added
    } = useContext(AppContext);

    const { setActiveView } = useUI();
    const { t, language } = useTranslation();

    // Categorias Principais
    const [activeCategory, setActiveCategory] = useState<'churches' | 'unidentified' | 'expenses'>('churches');

    // ID do Relatório Específico Selecionado (Ex: ID da Igreja)
    const [selectedReportId, setSelectedReportId] = useState<string | null>(null);

    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    // --- EFEITO: Seleção Inicial Automática ---
    useEffect(() => {
        if (!reportPreviewData) return;

        if (activeCategory === 'churches') {
            const churchIds = Object.keys(reportPreviewData.income).filter(k => k !== 'unidentified').sort();
            if (churchIds.length > 0) {
                // Se o ID selecionado não estiver na lista de igrejas, seleciona o primeiro
                if (!selectedReportId || !churchIds.includes(selectedReportId)) {
                    setSelectedReportId(churchIds[0]);
                }
            } else {
                setSelectedReportId(null);
            }
        } else if (activeCategory === 'unidentified') {
            setSelectedReportId('unidentified');
        } else if (activeCategory === 'expenses') {
            setSelectedReportId('all_expenses_group');
        }
    }, [activeCategory, reportPreviewData]);

    // --- DADOS CALCULADOS ---
    const churchList = useMemo(() => {
        if (!reportPreviewData?.income) return [];
        return Object.entries(reportPreviewData.income)
            .filter(([id]) => id !== 'unidentified')
            .map(([id, results]) => {
                const res = results as MatchResult[];
                return {
                    id,
                    name: res[0]?.church?.name || 'Igreja Desconhecida',
                    count: res.length,
                    total: res.reduce((sum, r) => sum + r.transaction.amount, 0)
                };
            })
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [reportPreviewData]);

    const counts = useMemo(() => {
        const churches = churchList.length;
        const pending = reportPreviewData?.income['unidentified']?.length || 0;
        const expenses = reportPreviewData?.expenses['all_expenses_group']?.length || 0;
        return { churches, pending, expenses };
    }, [churchList, reportPreviewData]);

    // Dados da Tabela Ativa
    const activeData = useMemo(() => {
        if (!reportPreviewData || !selectedReportId) return [];

        let data: MatchResult[] = [];
        if (activeCategory === 'expenses') {
            data = reportPreviewData.expenses[selectedReportId] || [];
        } else {
            data = reportPreviewData.income[selectedReportId] || [];
        }

        // Filtragem local por termo de busca
        if (searchTerm) {
            const lower = searchTerm.toLowerCase();
            data = data.filter(r => 
                (r.transaction.description || '').toLowerCase().includes(lower) ||
                (r.contributor?.name || '').toLowerCase().includes(lower) ||
                (r.contributor?.cleanedName || '').toLowerCase().includes(lower)
            );
        }

        return data;
    }, [reportPreviewData, selectedReportId, activeCategory, searchTerm]);

    const activeReportType = activeCategory === 'expenses' ? 'expenses' : 'income';

    // Totais do Relatório Ativo
    const activeSummary = useMemo(() => {
        const count = activeData.length;
        const total = activeData.reduce((sum, r) => sum + r.transaction.amount, 0);

        // Filtros
        const pendingTxs = activeData.filter(r => r.status === 'PENDENTE');
        const autoTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manualTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');

        // Contagens e Valores
        const pending = pendingTxs.length;
        const pendingValue = pendingTxs.reduce((sum, r) => sum + (r.contributorAmount || 0), 0);

        const auto = autoTxs.length;
        const autoValue = autoTxs.reduce((sum, r) => sum + r.transaction.amount, 0);

        const manual = manualTxs.length;
        const manualValue = manualTxs.reduce((sum, r) => sum + r.transaction.amount, 0);

        return { 
            count, total, 
            pending, pendingValue, 
            auto, autoValue, 
            manual, manualValue 
        };
    }, [activeData]);

    const handleSort = (key: string) => {
        setSortConfig(current => ({
            key,
            direction: current?.key === key && current.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const sortedData = useMemo(() => {
        if (!sortConfig) return activeData;
        return [...activeData].sort((a, b) => {
            let valA: any;
            let valB: any;

            if (sortConfig.key.includes('.')) {
                const parts = sortConfig.key.split('.');
                valA = parts.reduce((obj: any, k) => obj?.[k], a);
                valB = parts.reduce((obj: any, k) => obj?.[k], b);
            } else {
                valA = (a as any)[sortConfig.key];
                valB = (b as any)[sortConfig.key];
            }

            if (valA === undefined || valA === null) valA = '';
            if (valB === undefined || valB === null) valB = '';

            if (typeof valA === 'string') {
                valA = valA.toLowerCase();
                valB = valB.toLowerCase();
            }

            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [activeData, sortConfig]);

    const handleSaveReport = () => {
        const resultsToSave = matchResults;
        openSaveReportModal({
            type: 'global',
            results: resultsToSave,
            groupName: 'Geral'
        });
    };

    const handleDownload = () => {
        const headers = ["Data", "Descrição", "Tipo", "Status", "Valor"];
        const csvContent = [
            headers.join(";"),
            ...sortedData.map(r => {
                const date = formatDate(r.transaction.date);
                const desc = (r.contributor?.cleanedName || r.transaction.description).replace(/;/g, ' ');
                const type = (r.contributor?.contributionType || r.transaction.contributionType || "").replace(/;/g, ' ');
                const status = r.status === 'IDENTIFICADO' ? (r.matchMethod || 'AUTO') : r.status;
                // Formata para padrão brasileiro no CSV (vírgula decimal)
                const amount = (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : r.transaction.amount)
                    .toFixed(2).replace('.', ',');

                return [`"${date}"`, `"${desc}"`, `"${type}"`, `"${status}"`, `"${amount}"`].join(";");
            })
        ].join("\n");

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `relatorio_${new Date().toISOString().slice(0,10)}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (!printWindow) return;

        const title = activeCategory === 'churches' 
            ? (churchList.find(c => c.id === selectedReportId)?.name || 'Relatório de Igreja')
            : activeCategory === 'unidentified' ? 'Transações Pendentes' : 'Saídas e Despesas';

        const tableRows = sortedData.map(r => {
            const date = formatDate(r.transaction.date);
            const name = r.contributor?.cleanedName || r.contributor?.name || r.transaction.cleanedDescription || r.transaction.description;
            const amount = formatCurrency(r.status === 'PENDENTE' ? (r.contributorAmount || 0) : r.transaction.amount, language);
            const type = r.contributor?.contributionType || r.transaction.contributionType || '---';
            const status = r.status === 'IDENTIFICADO' ? (r.matchMethod || 'AUTO') : r.status;

            return `
                <tr>
                    <td>${date}</td>
                    <td>${name}</td>
                    <td style="text-align: center;">${type}</td>
                    <td style="text-align: center;">${status}</td>
                    <td style="text-align: right;">${amount}</td>
                </tr>
            `;
        }).join('');

        printWindow.document.write(`
            <html>
                <head>
                    <title>${title} - IdentificaPix</title>
                    <style>
                        body { font-family: 'Inter', sans-serif; padding: 20px; color: #1e293b; }
                        h1 { font-size: 20px; margin-bottom: 5px; text-transform: uppercase; }
                        p { margin: 0 0 20px 0; color: #64748b; font-size: 12px; }
                        .summary { display: flex; gap: 20px; margin-bottom: 20px; padding: 15px; background: #f8fafc; border-radius: 8px; border: 1px solid #e2e8f0; }
                        .summary-item { display: flex; flex-direction: column; }
                        .summary-label { font-size: 10px; font-weight: bold; text-transform: uppercase; color: #64748b; }
                        .summary-value { font-size: 14px; font-weight: bold; color: #0f172a; }
                        table { width: 100%; border-collapse: collapse; font-size: 11px; }
                        th { text-align: left; background: #f1f5f9; padding: 8px; border-bottom: 2px solid #cbd5e1; text-transform: uppercase; font-size: 10px; color: #475569; }
                        td { padding: 8px; border-bottom: 1px solid #e2e8f0; }
                        tr:nth-child(even) { background: #f8fafc; }
                    </style>
                </head>
                <body>
                    <h1>${title}</h1>
                    <p>Gerado em: ${new Date().toLocaleString()}</p>

                    <div class="summary">
                        <div class="summary-item">
                            <span class="summary-label">Quantidade</span>
                            <span class="summary-value">${activeSummary.count}</span>
                        </div>
                        <div class="summary-item">
                            <span class="summary-label">Total</span>
                            <span class="summary-value">${formatCurrency(activeSummary.total, language)}</span>
                        </div>
                    </div>

                    <table>
                        <thead>
                            <tr>
                                <th style="width: 15%">Data</th>
                                <th style="width: 45%">Nome / Descrição</th>
                                <th style="width: 15%; text-align: center;">Tipo</th>
                                <th style="width: 10%; text-align: center;">Status</th>
                                <th style="width: 15%; text-align: right;">Valor</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${tableRows}
                        </tbody>
                    </table>
                    <script>
                        window.onload = function() { window.print(); }
                    </script>
                </body>
            </html>
        `);
        printWindow.document.close();
    };

    const handleRowChange = (updatedRow: MatchResult) => {
        updateReportData(updatedRow, activeReportType);
    };

    const handleEdit = (row: MatchResult) => {
        openSmartEdit(row);
    };

    // Componente de Botão de Categoria (Compacto e com Gradiente)
    const CategoryPill = ({ id, label, count, icon: Icon }: any) => {
        const isActive = activeCategory === id;

        let activeClass = "";
        let iconClass = "";

        if (id === 'churches') {
            activeClass = "bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-md shadow-blue-500/30";
            iconClass = isActive ? "text-white" : "text-blue-500";
        } else if (id === 'unidentified') {
            activeClass = "bg-gradient-to-r from-amber-500 to-orange-500 text-white shadow-md shadow-orange-500/30";
            iconClass = isActive ? "text-white" : "text-amber-500";
        } else {
            activeClass = "bg-gradient-to-r from-rose-500 to-red-600 text-white shadow-md shadow-red-500/30";
            iconClass = isActive ? "text-white" : "text-rose-500";
        }

        const baseClass = "bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700";

        return (
            <button
                onClick={() => setActiveCategory(id)}
                className={`
                    relative flex items-center gap-2 px-3 py-1.5 rounded-full transition-all duration-300 text-[10px] font-bold uppercase tracking-wide
                    ${isActive ? `${activeClass} transform scale-105 z-10 border-transparent` : baseClass}
                `}
            >
                <Icon className={`w-3.5 h-3.5 ${iconClass}`} />
                <span>{label}</span>
                <span className={`px-1.5 py-0.5 rounded-md text-[9px] leading-none ${isActive ? 'bg-white/20 text-white' : 'bg-slate-100 dark:bg-slate-900 text-slate-500'}`}>
                    {count}
                </span>
            </button>
        );
    };

    // Componente de Botão de Igreja (Compacto)
    const ChurchChip: React.FC<{ item: { id: string; name: string; count: number; total: number } }> = ({ item }) => {
        const isSelected = selectedReportId === item.id;
        return (
            <button
                onClick={() => setSelectedReportId(item.id)}
                className={`
                    flex-shrink-0 flex items-center gap-2 px-3 py-1 rounded-full border transition-all duration-200 text-xs
                    ${isSelected 
                        ? 'bg-gradient-to-r from-blue-50 to-indigo-50 border-blue-200 text-blue-700 shadow-sm ring-1 ring-blue-100 dark:from-blue-900/40 dark:to-indigo-900/40 dark:border-blue-800 dark:text-blue-300' 
                        : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:border-blue-300 dark:hover:border-slate-500'
                    }
                `}
            >
                {isSelected && <div className="w-1.5 h-1.5 rounded-full bg-blue-600 shadow-[0_0_5px_rgba(37,99,235,0.6)]"></div>}
                <span className="font-bold truncate max-w-[150px]">{item.name}</span>
                <span className={`px-1.5 rounded text-[10px] font-bold ${isSelected ? 'bg-white/50 dark:bg-black/20' : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'}`}>
                    {item.count}
                </span>
            </button>
        );
    };

    if (!reportPreviewData) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState
                    icon={<ChartBarIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />}
                    title={t('empty.reports.title')}
                    message={t('empty.reports.message')}
                    action={{
                        text: t('empty.dashboard.saved.action'),
                        onClick: () => setActiveView('upload'),
                    }}
                />
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full animate-fade-in gap-2 pb-2 px-1">

            {/* 1. TOP BAR COMPACTADA: Title & Controls */}
            <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-2 flex-shrink-0">
                <div className="flex items-center gap-4">
                    <h2 className="text-lg font-black text-brand-deep dark:text-white tracking-tight leading-none">{t('reports.title')}</h2>

                    {/* CATEGORY TABS (Compact) */}
                    <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-900/50 p-0.5 rounded-full border border-slate-200 dark:border-slate-800">
                        <CategoryPill 
                            id="churches" 
                            label="Igrejas" 
                            count={counts.churches} 
                            icon={BuildingOfficeIcon} 
                        />
                        <CategoryPill 
                            id="unidentified" 
                            label="Pendentes" 
                            count={counts.pending} 
                            icon={ExclamationTriangleIcon} 
                        />
                        <CategoryPill 
                            id="expenses" 
                            label="Saídas" 
                            count={counts.expenses} 
                            icon={BanknotesIcon} 
                        />
                    </div>
                </div>

                {/* ACTIONS (RIGHT) - Separated buttons for clear function distinction */}
                <div className="flex items-center gap-2 w-full md:w-auto ml-auto">

                    {/* NEW BUTTON: Manage Source Files */}
                    <button 
                        onClick={openUpdateFilesModal}
                        className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-[10px] font-bold text-slate-600 dark:text-slate-300 hover:text-indigo-600 hover:border-indigo-200 transition-all shadow-sm hover:shadow-md active:scale-95"
                        title="Adicionar ou substituir arquivos"
                    >
                        <FolderPlusIcon className="w-3.5 h-3.5" />
                        <span>Gerenciar Arquivos</span>
                    </button>

                    <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1"></div>

                    {/* Botões Discretos (Download & Print) */}
                    <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 rounded-full p-1 mr-2 border border-slate-200 dark:border-slate-700">
                        <button 
                            onClick={handleDownload}
                            className="p-1.5 rounded-full text-slate-400 hover:text-brand-blue hover:bg-white dark:hover:bg-slate-700 transition-all"
                            title="Baixar CSV"
                        >
                            <DocumentArrowDownIcon className="w-4 h-4" />
                        </button>
                        <div className="w-px h-3 bg-slate-300 dark:bg-slate-600"></div>
                        <button 
                            onClick={handlePrint}
                            className="p-1.5 rounded-full text-slate-400 hover:text-brand-blue hover:bg-white dark:hover:bg-slate-700 transition-all"
                            title="Imprimir"
                        >
                            <PrinterIcon className="w-4 h-4" />
                        </button>
                    </div>

                    {/* Botão Salvar Alterações (Revertido para Estilo Original) */}
                    {activeReportId && (
                        <button 
                            onClick={saveCurrentReportChanges}
                            className="relative flex items-center justify-center gap-2 px-4 py-2 rounded-full text-[10px] uppercase font-bold text-white bg-gradient-to-r from-amber-500 to-orange-500 hover:from-amber-600 hover:to-orange-600 shadow-lg shadow-orange-500/20 hover:-translate-y-0.5 transition-all active:scale-95"
                        >
                            <FloppyDiskIcon className="w-3.5 h-3.5" />
                            <span>Salvar Alt.</span>
                        </button>
                    )}

                    {/* Botão Salvar Novo Relatório (Revertido para Estilo Original) */}
